def range_summary(nums):
    if not nums:
        return ''

    nums = sorted(set(nums))
    summary_parts = []
    start = end = nums[0]

    for num in nums[1:]:
        if num == end + 1:
            end = num
        else:
            if start == end:
                summary_parts.append(str(start))
            else:
                summary_parts.append(f'{start}-{end}')
            start = end = num

    # Add the last range or number
    if start == end:
        summary_parts.append(str(start))
    else:
        summary_parts.append(f'{start}-{end}')

    return ', '.join(summary_parts)
